// server.js
require('dotenv').config();
const express = require('express');
const app = express();
const userRoutes = require('./routes/userRoutes');

// Middleware to parse JSON bodies
app.use(express.json());

// Basic route
app.get('/', (req, res) => {
    res.send('Welcome to the PostgreSQL CRUD API!');
});

// Mount user routes
app.use('/users', userRoutes);

// Error handling middleware (optional, but good practice)
app.use((err, req, res, next) => {
    console.error(err.stack);
    res.status(500).send('Something broke!');
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
});

// db.js
const { Pool } = require('pg');

const pool = new Pool({
    user: process.env.DB_USER,
    host: process.env.DB_HOST,
    database: process.env.DB_DATABASE,
    password: process.env.DB_PASSWORD,
    port: process.env.DB_PORT,
});

pool.on('connect', () => {
    console.log('Connected to the PostgreSQL database!');
});

pool.on('error', (err) => {
    console.error('Error connecting to the database:', err.message);
    process.exit(-1); // Exit process on database connection error
});

module.exports = {
    query: (text, params) => pool.query(text, params),
};

// models/userModel.js
const db = require('../db');

class UserModel {
    static async create(user) {
        const { name, email } = user;
        const query = 'INSERT INTO users (name, email) VALUES ($1, $2) RETURNING *';
        const { rows } = await db.query(query, [name, email]);
        return rows[0];
    }

    static async findAll() {
        const query = 'SELECT * FROM users ORDER BY id ASC';
        const { rows } = await db.query(query);
        return rows;
    }

    static async findById(id) {
        const query = 'SELECT * FROM users WHERE id = $1';
        const { rows } = await db.query(query, [id]);
        return rows[0];
    }

    static async update(id, user) {
        const { name, email } = user;
        const query = 'UPDATE users SET name = $1, email = $2 WHERE id = $3 RETURNING *';
        const { rows } = await db.query(query, [name, email, id]);
        return rows[0];
    }

    static async remove(id) {
        const query = 'DELETE FROM users WHERE id = $1 RETURNING *';
        const { rows } = await db.query(query, [id]);
        return rows[0];
    }
}

module.exports = UserModel;

// routes/userRoutes.js
const express = require('express');
const router = express.Router();
const UserModel = require('../models/userModel');

// Create a new user
router.post('/', async (req, res) => {
    try {
        const newUser = await UserModel.create(req.body);
        res.status(201).json(newUser);
    } catch (err) {
        if (err.code === '23505') { // Unique violation error code
            return res.status(409).json({ error: 'Email already exists.' });
        }
        res.status(500).json({ error: err.message });
    }
});

// Get all users
router.get('/', async (req, res) => {
    try {
        const users = await UserModel.findAll();
        res.status(200).json(users);
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

// Get a single user by ID
router.get('/:id', async (req, res) => {
    try {
        const user = await UserModel.findById(req.params.id);
        if (!user) {
            return res.status(404).json({ error: 'User not found' });
        }
        res.status(200).json(user);
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

// Update a user by ID
router.put('/:id', async (req, res) => {
    try {
        const updatedUser = await UserModel.update(req.params.id, req.body);
        if (!updatedUser) {
            return res.status(404).json({ error: 'User not found' });
        }
        res.status(200).json(updatedUser);
    } catch (err) {
        if (err.code === '23505') { // Unique violation error code
            return res.status(409).json({ error: 'Email already exists.' });
        }
        res.status(500).json({ error: err.message });
    }
});

// Delete a user by ID
router.delete('/:id', async (req, res) => {
    try {
        const deletedUser = await UserModel.remove(req.params.id);
        if (!deletedUser) {
            return res.status(404).json({ error: 'User not found' });
        }
        res.status(200).json({ message: 'User deleted successfully', user: deletedUser });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

module.exports = router;

